-- Edgar-Ellen (DialogueBuilder)
local npc = DialogueBuilder:new("Edgar-Ellen",
	{lookType = 132, lookBody = 39, lookLegs = 99, lookFeet = 116})
npc:greetMessage("This world is nothing without poetry, don't you think? It gives us hope, it envokes love. It's inciting and invigorating all the same.")
npc:farewellMessage("Goodbye and farewell, my friend.")
npc:addResponse("tibia", "Our world, our home, our very own plane of existence. We have to protect it, mind you. Underneath all the battles, challenges and monsters there still resides a majestic, yet vulnerable being. A mother to us all.")
npc:addResponse("king", "A king and a beggar know more than a king alone... ahem, except for King Tibianus. He most certainly would. All hail King Tibianus etc. etc.")
npc:addResponse("mission", "So, you're on a mission. Aren't we all? A quest to savour the important moments, the valuable memories? To fight for love and happiness, heroically and against all odds? Yes, we are indeed.")
npc:addResponse("quest", "So, you're on a mission. Aren't we all? A quest to savour the important moments, the valuable memories? To fight for love and happiness, heroically and against all odds? Yes, we are indeed.")
npc:addResponse("job", "Rather a calling. The weight of words is something not easily lifted by some, yet it can be a mighty weapon to others. ...")
npc:register()
